import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import JobService from '../services/JobService';

function JobList() {
  const navigate = useNavigate();
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    keyword: '',
    location: '',
    minSalary: '',
    employmentType: ''
  });

  useEffect(() => {
    fetchJobs();
  }, []);

  const fetchJobs = async () => {
    try {
      const response = await JobService.getJobs();
      setJobs(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Failed to fetch jobs', error);
      setLoading(false);
    }
  };

  const handleFilterChange = (e) => {
    setFilters({
      ...filters,
      [e.target.name]: e.target.value
    });
  };

  const handleSearch = () => {
    // TODO: Implement filtering logic in backend
    fetchJobs();
  };

  const handleViewDetails = (jobId) => {
    navigate(`/jobs/${jobId}`);
  };

  if (loading) return <div className="container"><p>Đang tải...</p></div>;

  return (
    <div className="container">
      <h2>Danh Sách Công Việc</h2>
      
      <div className="filter-section">
        <input
          type="text"
          name="keyword"
          placeholder="Từ khóa"
          value={filters.keyword}
          onChange={handleFilterChange}
        />
        <input
          type="text"
          name="location"
          placeholder="Địa điểm"
          value={filters.location}
          onChange={handleFilterChange}
        />
        <input
          type="number"
          name="minSalary"
          placeholder="Lương tối thiểu"
          value={filters.minSalary}
          onChange={handleFilterChange}
        />
        <select
          name="employmentType"
          value={filters.employmentType}
          onChange={handleFilterChange}
        >
          <option value="">Tất cả loại hình</option>
          <option value="Full-time">Full-time</option>
          <option value="Part-time">Part-time</option>
        </select>
        <button onClick={handleSearch} className="btn btn-primary">Tìm kiếm</button>
      </div>

      <div className="job-list">
        {jobs.length === 0 ? (
          <p>Không có công việc nào</p>
        ) : (
          jobs.map((job) => (
            <div key={job.id} className="job-card">
              <h3>{job.title}</h3>
              <p className="job-company">Công ty: {job.employer?.username || 'N/A'}</p>
              <p className="job-description">{job.description?.substring(0, 150)}...</p>
              
              <div className="job-meta-inline">
                <span>📍 {job.location || 'N/A'}</span>
                <span>💼 {job.employmentType || 'N/A'}</span>
                <span>💰 ${job.salary?.toLocaleString() || 'Thỏa thuận'}</span>
              </div>
              
              <button 
                className="btn btn-primary"
                onClick={() => handleViewDetails(job.id)}
              >
                Xem Chi Tiết
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default JobList;
